242	export default tool({
243	  name: 'vision-apply',
244	  description: 'Apply an on-disk vision (snapshot a directory into a vision writ + VisionDoc)',
245	  instructions:
246	    'Reads <guildHome>/vision/<slug>/{vision.md, vision-metadata.yml}, snapshots the ' +
247	    'vision into the cartograph as a vision writ + companion VisionDoc, and writes a ' +
248	    'priority-hint payload into writ.ext[surveyor]. On first apply, the sidecar gains a ' +
249	    'visionId field binding the directory to its writ. On subsequent applies, the bound ' +
250	    'writ is updated in place; missing/cancelled/completed/failed bindings error cleanly. ' +
251	    'CLI flags --severity, --deadline, and --decay override sidecar values for the ' +
