268	    const { slug } = params;
269	    // Defensive — Zod regex already enforces, but a structurally-typed
270	    // caller could bypass at the type boundary.
271	    if (slug.includes('/') || slug.includes('\\') || slug === '..' || slug.startsWith('.')) {
272	      throw new Error(
273	        `[vision-apply] slug "${slug}" is not a valid directory name (no path separators, no leading dots, no "..").`,
274	      );
275	    }
276	
277	    const home = guild().home;
278	    const visionDir = path.join(home, 'vision', slug);
279	    const visionMdPath = path.join(visionDir, 'vision.md');
280	    const sidecarPath = path.join(visionDir, 'vision-metadata.yml');
281	
282	    // Load both files. Errors are caught and re-thrown with a friendly
283	    // message so the patron sees "missing sidecar" rather than ENOENT.
284	    let bodyText: string;
285	    try {
286	      bodyText = await readFile(visionMdPath, 'utf8');
287	    } catch (err) {
288	      const errno = (err as NodeJS.ErrnoException).code;
289	      if (errno === 'ENOENT') {
290	        throw new Error(
291	          `[vision-apply] vision.md not found at "${visionMdPath}". Create the file or check the slug.`,
292	        );
293	      }
294	      throw err;
295	    }
296	
297	    let sidecarRaw: string;
298	    try {
299	      sidecarRaw = await readFile(sidecarPath, 'utf8');
300	    } catch (err) {
301	      const errno = (err as NodeJS.ErrnoException).code;
302	      if (errno === 'ENOENT') {
