1	/**
2	 * Shared text/JSON rendering helpers used by the cartograph CLI tools.
3	 *
4	 * Each cartograph type (vision, charge, piece) has its own create/show/list/
5	 * patch/transition tools, but the show and list rendering behavior is
6	 * byte-shape identical across the three. These helpers centralize the
7	 * composition (companion doc + writ row + links + descendants summary +
8	 * children list + parent ref) and the table/block rendering so the per-
9	 * type tools stay thin.
10	 *
11	 * Decision references (from the commission spec):
12	 *   - D7 / D8  — show composes the doc with the writ row; JSON shape is
13	 *               `{ ...doc, writ: { ... } }` to avoid id/timestamp collisions.
14	 *   - D9       — list table columns: [stage, id, codex, title, created],
15	 *               with per-row title fetch from the writ rows (N+1 cost).
16	 *   - D18      — show text-mode mirrors writ-show's lifecycle-aware block.
17	 */
18	
19	import { shortId } from '@shardworks/nexus-core';
20	import type {
21	  ClerkApi,
22	  WritDoc,
23	  WritLinks,
24	  WritPhase,
25	  WritTypeConfig,
26	  WritTypeStateAttr,
27	  WritTypeStateClassification,
28	} from '@shardworks/clerk-apparatus';
29	
30	// ── Types ────────────────────────────────────────────────────────────
31	
32	/** Subset of `WritDoc` fields nested under `writ` in the show JSON shape (D8). */
33	export interface WritProjection {
34	  id: string;
35	  title: string;
36	  body: string;
37	  type: string;
38	  phase: string;
39	  parentId?: string;
40	  codex?: string;
41	  createdAt: string;
42	  updatedAt: string;
43	  resolvedAt?: string;
44	  resolution?: string;
45	}
46	
47	/** Reference shape for parent + children entries in a show response. */
48	export interface WritReference {
49	  id: string;
50	  title: string;
51	  type: string;
52	  phase: string;
53	}
54	
55	/**
56	 * Composed result returned by `composeShow(...)`. The cartograph doc's
57	 * fields land at the top level (so the response is recognizably the
58	 * companion doc); the underlying writ row sits nested under `writ` to
59	 * avoid id/timestamp field collisions (D8). The supplementary fields
60	 * (`parent`, `children`, `links`) drive the text-mode renderer.
61	 */
62	export interface CartographShowResult<TDoc extends Record<string, unknown>> {
63	  doc: TDoc;
64	  writ: WritProjection;
65	  links: WritLinks;
66	  parent: WritReference | null;
67	  children: { summary: Record<WritPhase, number>; items: WritReference[] };
68	  /** Classification + attrs for the top-level writ; drives the text block. */
69	  classification: WritTypeStateClassification | 'unknown';
70	  allowedTransitions: string[];
71	  attrs: WritTypeStateAttr[];
72	}
73	
74	// ── Helpers ──────────────────────────────────────────────────────────
75	
76	/**
77	 * Project a writ-shaped record onto the JSON-mode subset declared by D8.
78	 * Only the fields that survive the `{ ...doc, writ }` nesting are kept;
79	 * additional metadata (`type`, `phase`, `parentId`, `resolvedAt`,
80	 * `resolution`) ride alongside so a reader does not need a second
81	 * round-trip to clerk.show.
82	 */
83	export function projectWrit(writ: WritDoc): WritProjection {
84	  const projection: WritProjection = {
85	    id: writ.id,
86	    title: writ.title,
87	    body: writ.body,
88	    type: writ.type,
89	    phase: writ.phase,
90	    createdAt: writ.createdAt,
91	    updatedAt: writ.updatedAt,
92	  };
93	  if (writ.parentId !== undefined) projection.parentId = writ.parentId;
94	  if (writ.codex !== undefined) projection.codex = writ.codex;
95	  if (writ.resolvedAt !== undefined) projection.resolvedAt = writ.resolvedAt;
96	  if (writ.resolution !== undefined) projection.resolution = writ.resolution;
97	  return projection;
98	}
99	
100	/**
101	 * Project a writ row onto the bare reference shape used in `parent` and
102	 * `children.items`. Tighter than `WritProjection` — the reference shape
103	 * carries only what the renderer prints.
104	 */
105	function projectReference(writ: WritDoc): WritReference {
106	  return { id: writ.id, title: writ.title, type: writ.type, phase: writ.phase };
107	}
108	
109	/**
110	 * Look up the lifecycle classification + outbound transitions + attrs for
111	 * a writ. Mirrors clerk's `derivePresentation` by hand because that helper
112	 * is not exported from the package's public surface; replicating the
113	 * minimal logic lets cartograph stay decoupled from clerk's internals.
114	 */
115	function projectPresentation(
116	  writ: Pick<WritDoc, 'type' | 'phase'>,
117	  getConfig: (name: string) => WritTypeConfig | undefined,
118	): {
119	  classification: WritTypeStateClassification | 'unknown';
120	  allowedTransitions: string[];
121	  attrs: WritTypeStateAttr[];
122	} {
123	  const config = getConfig(writ.type);
124	  if (!config) return { classification: 'unknown', allowedTransitions: [], attrs: [] };
125	  const state = config.states.find((s) => s.name === writ.phase);
126	  if (!state) return { classification: 'unknown', allowedTransitions: [], attrs: [] };
127	  return {
128	    classification: state.classification,
129	    allowedTransitions: [...state.allowedTransitions],
130	    attrs: [...(state.attrs ?? [])],
131	  };
132	}
133	
134	/**
135	 * Compose the show response for a cartograph type. The caller supplies
136	 * the typed-API show result (the companion doc) and the clerk apparatus
137	 * handle; this helper fetches the writ row, parent ref, children list,
138	 * descendants summary, and links in parallel.
139	 */
140	export async function composeShow<TDoc extends Record<string, unknown>>(
141	  doc: TDoc,
142	  id: string,
143	  clerk: ClerkApi,
144	): Promise<CartographShowResult<TDoc>> {
145	  const [writ, links, summary] = await Promise.all([
146	    clerk.show(id),
147	    clerk.links(id),
148	    clerk.countDescendantsByPhase(id),
149	  ]);
150	
151	  let parent: WritReference | null = null;
152	  if (writ.parentId) {
153	    const parentWrit = await clerk.show(writ.parentId);
154	    parent = projectReference(parentWrit);
155	  }
156	
157	  const childWrits = await clerk.list({ parentId: writ.id, limit: 1000 });
158	  const items: WritReference[] = childWrits.map(projectReference);
159	
160	  const presentation = projectPresentation(writ, (name) =>
161	    clerk.getWritTypeConfig(name),
162	  );
163	
164	  return {
165	    doc,
166	    writ: projectWrit(writ),
167	    links,
168	    parent,
169	    children: { summary, items },
170	    classification: presentation.classification,
171	    allowedTransitions: presentation.allowedTransitions,
172	    attrs: presentation.attrs,
173	  };
174	}
175	
176	// ── Show text rendering ──────────────────────────────────────────────
177	
178	/**
179	 * Render the lifecycle-aware text block for a cartograph show response
180	 * (D18). Mirrors writ-show's structural shape: identity, state
181	 * (classification + attrs), allowed transitions, codex, parent ref,
182	 * timestamps, body, descendants summary, children list, links. Adds a
183	 * cartograph-specific `Stage:` row above `State:` so the patron sees both
184	 * the writ phase and the companion-doc stage at a glance.
185	 */
186	export function renderShowText<TDoc extends { stage: string }>(
187	  typeLabel: string,
188	  result: CartographShowResult<TDoc>,
189	): string {
190	  const { doc, writ, parent, children, links, classification, allowedTransitions, attrs } = result;
191	  const lines: string[] = [];
192	
193	  // ── Identity row ──
194	  lines.push(`${typeLabel}:    ${writ.title}`);
195	  lines.push(`Id:        ${shortId(writ.id)}  (${writ.id})`);
196	  lines.push(`Type:      ${writ.type}`);
197	
198	  // ── Stage / State annotation ──
199	  lines.push(`Stage:     ${doc.stage}`);
200	  const attrSegment = attrs.length > 0 ? `, attrs: [${attrs.join(', ')}]` : '';
201	  lines.push(`Phase:     ${writ.phase}  (classification: ${classification}${attrSegment})`);
202	
203	  const transitionsLabel =
204	    allowedTransitions.length === 0
205	      ? '(none — terminal or unknown state)'
206	      : allowedTransitions.join(', ');
207	  lines.push(`Transitions: ${transitionsLabel}`);
208	
209	  if (writ.codex) lines.push(`Codex:     ${writ.codex}`);
210	  if (parent) {
211	    lines.push(`Parent:    ${shortId(parent.id)}  ${parent.title}  (${parent.phase})`);
212	  }
213	
214	  // ── Timestamps ──
215	  lines.push('');
216	  lines.push(`Created:   ${writ.createdAt}`);
217	  lines.push(`Updated:   ${writ.updatedAt}`);
218	  if (writ.resolvedAt) lines.push(`Resolved:  ${writ.resolvedAt}`);
219	  if (writ.resolution) lines.push(`Resolution: ${writ.resolution}`);
220	
221	  // ── Body ──
222	  if (writ.body) {
223	    lines.push('');
224	    lines.push('Body:');
225	    for (const ln of writ.body.split('\n')) lines.push(`  ${ln}`);
226	  }
227	
228	  // ── Descendant phase summary ──
229	  const summaryEntries = Object.entries(children.summary);
230	  if (summaryEntries.length > 0) {
231	    lines.push('');
232	    lines.push('Descendants:');
233	    for (const [phase, count] of summaryEntries) {
234	      lines.push(`  ${phase}: ${count}`);
235	    }
236	  }
237	
238	  // ── Direct-children list ──
239	  if (children.items.length > 0) {
240	    lines.push('');
241	    lines.push('Children:');
242	    for (const child of children.items) {
243	      lines.push(`  ${shortId(child.id)}  ${child.phase.padEnd(10)}  ${child.title}`);
244	    }
245	  }
246	
247	  // ── Links ──
248	  const outbound = links.outbound ?? [];
249	  const inbound = links.inbound ?? [];
250	  if (outbound.length > 0 || inbound.length > 0) {
251	    lines.push('');
252	    lines.push('Links:');
253	    for (const l of outbound) lines.push(`  → ${shortId(l.targetId)}  (${l.label})`);
254	    for (const l of inbound) lines.push(`  ← ${shortId(l.sourceId)}  (${l.label})`);
255	  }
256	
257	  return lines.join('\n');
258	}
259	
260	/**
261	 * Build the JSON output shape per D8: `{ ...doc, writ: { ... } }`. Doc
262	 * fields land at the top level; writ-side fields stay nested to dodge
263	 * id/timestamp collisions.
264	 */
265	export function renderShowJson<TDoc extends Record<string, unknown>>(
266	  result: CartographShowResult<TDoc>,
267	): TDoc & { writ: WritProjection } {
268	  return { ...result.doc, writ: result.writ };
269	}
270	
271	// ── List text rendering ──────────────────────────────────────────────
272	
273	/**
274	 * Row shape consumed by `renderListTable`. The table columns are
275	 * `[stage, id, codex, title, created]` per D9; the per-row title is
276	 * fetched from the writ row by the caller (N+1 cost is acceptable for v0).
277	 */
278	export interface ListRow {
279	  stage: string;
280	  id: string;
281	  codex?: string;
282	  title: string;
283	  createdAt: string;
284	}
285	
286	/**
287	 * Render a tabular text view of cartograph list rows (D9). Columns are
288	 * padded to the widest cell so heterogeneous values stay aligned; the
