    '`registerWritType`, including the Clerk\'s own `mandate`. Each entry ' +
    'reports the type name, source (`builtin` or `plugin`), and whether ' +
    'it is the default type.',
  params: {},
  permission: 'read',
  handler: async () => api.listWritTypes(),
});

