1	/**
2	 * Shared field access and order-by utilities.
3	 *
4	 * Used by both the apparatus-level logic (stacks-core.ts) and the
5	 * memory backend (memory-backend.ts). Kept in a minimal module with
6	 * no heavy dependencies.
7	 */
8	
9	import type { BookEntry, OrderBy } from './types.ts';
10	
11	/**
12	 * Access a potentially nested field via dot-notation (e.g. "parent.id").
13	 */
14	export function getNestedField(obj: BookEntry | Record<string, unknown>, field: string): unknown {
15	  const parts = field.split('.');
16	  let current: unknown = obj;
17	  for (const part of parts) {
18	    if (current == null || typeof current !== 'object') return undefined;
19	    current = (current as Record<string, unknown>)[part];
20	  }
21	  return current;
22	}
23	
24	/**
25	 * Normalize the public OrderBy type into a uniform array of { field, dir }.
26	 *
27	 * Does NOT validate field names — callers are responsible for ensuring
28	 * fields have already been validated (e.g. via translateQuery) before
29	 * reaching this point. translateQuery calls validateFieldName after
30	 * normalizing because it sits at the untrusted-input boundary.
31	 */
32	export function normalizeOrderBy(
33	  orderBy: OrderBy,
34	): Array<{ field: string; dir: 'asc' | 'desc' }> {
35	  if (typeof orderBy[0] === 'string') {
36	    const [field, dir] = orderBy as [string, 'asc' | 'desc'];
37	    return [{ field, dir }];
38	  }
39	  return (orderBy as Array<[string, 'asc' | 'desc']>).map(([field, dir]) => ({
40	    field,
41	    dir,
42	  }));
43	}
44	
45	/**
46	 * Compare two entries by a list of order-by entries.
47	 *
48	 * Shared by the memory backend's sortEntries and the apparatus-level
49	 * OR query re-sort in stacks-core.ts. Null values sort before non-null
50	 * in ascending order, after non-null in descending order.
51	 */
52	export function compareByOrderEntries(
53	  a: BookEntry | Record<string, unknown>,
54	  b: BookEntry | Record<string, unknown>,
55	  orderEntries: Array<{ field: string; dir: 'asc' | 'desc' }>,
56	): number {
57	  for (const { field, dir } of orderEntries) {
58	    const va = getNestedField(a, field);
59	    const vb = getNestedField(b, field);
60	    if (va === vb) continue;
61	    if (va == null) return dir === 'asc' ? -1 : 1;
62	    if (vb == null) return dir === 'asc' ? 1 : -1;
63	    const cmp = va < vb ? -1 : 1;
64	    return dir === 'asc' ? cmp : -cmp;
65	  }
66	  return 0;
67	}
68

