1	/**
2	 * Astrolabe — public types.
3	 *
4	 * PlanDoc, ScopeItem, Decision, and supporting types for the brief-to-spec
5	 * planning pipeline.
6	 */
7	
8	// ── Plan status ──────────────────────────────────────────────────────
9	
10	export type PlanStatus = 'reading' | 'analyzing' | 'reviewing' | 'writing' | 'completed' | 'failed';
11	
12	// ── Documents ────────────────────────────────────────────────────────
13	
14	export interface PlanDoc {
15	  [key: string]: unknown;
16	  /** The brief writ ID — primary key. */
17	  id: string;
18	  /** The codex this plan targets. */
19	  codex: string;
20	  /** Planning status. */
21	  status: PlanStatus;
22	
23	  // ── Reader output ───────────────────────────────────────────
24	  /** Codebase inventory: affected files, types, interfaces, patterns. */
25	  inventory?: string;
26	
27	  // ── Primer output ───────────────────────────────────────────
28	  /**
29	   * Primer observations: refactoring opportunities, risks, conventions.
30	   *
31	   * Each entry is an atomic, commissionable concern — the
32	   * `astrolabe.observation-lift` engine lifts each record into a draft
33	   * top-level `mandate` writ (never a child of the originating mandate),
34	   * attaching an `astrolabe.lifted-from` provenance edge back to the
35	   * originating mandate. When the plan yields two or more observations,
36	   * the engine additionally groups the drafts under a top-level
37	   * `observation-set` container. A curator (human or automated) then
38	   * promotes each draft to open status.
39	   */
40	  observations?: Observation[];
41	  /** Scope items: what's in and what's out. */
42	  scope?: ScopeItem[];
43	  /** Architectural/design decisions with options. */
44	  decisions?: Decision[];
45	
46	  // ── Spec-writer output ──────────────────────────────────────
47	  /** The generated specification. */
48	  spec?: string;
49	  /**
50	   * Legacy: writ id of a mandate produced by the retired `spec-publish`
51	   * engine. Current rig templates do not set this field — it survives
52	   * solely so historic plandocs stored from before the retirement
53	   * continue to deserialise and render correctly in the Astrolabe page.
54	   */
55	  generatedWritId?: string;
56	  /**
57	   * Count of distinct path tokens predicted by the spec's task-manifest
58	   * `<files>` elements at planning time — recorded by the
59	   * `astrolabe.plan-finalize` engine on every completed plan as the
60	   * predicted-files-touched cost signal. Set to 0 when the spec contains
61	   * no `<task-manifest>` block (or no recognisable path tokens). This is
62	   * a measurement layer only — the framework records the signal; downstream
63	   * subscribers (sanctum-side instrumentation, future auto-decompose) decide
64	   * what to do with it.
65	   */
66	  manifestFilesCount?: number;
67	
68	  createdAt: string;
69	  updatedAt: string;
70	}
71	
72	export interface ScopeItem {
73	  id: string;
74	  description: string;
75	  rationale: string;
76	  included: boolean;
77	}
78	
79	/**
80	 * A single observation recorded by a sage during the planning pass.
81	 *
82	 * Each observation names one concern — a refactoring opportunity,
83	 * risk, convention drift, or bug — that the sage noticed but that
84	 * is outside the brief's scope. Observations flow downstream into
85	 * the `astrolabe.observation-lift` engine, which lifts each record
86	 * into a draft top-level `mandate` writ (never a child of the
87	 * originating mandate). The provenance relationship rides on the
88	 * kit-registered `astrolabe.lifted-from` link kind. When a plan
89	 * yields two or more observations, the engine additionally groups
90	 * the drafts under a top-level `observation-set` container.
91	 *
92	 * Fields are deliberately minimal (D1 in the commission spec):
93	 * - `id` — plandoc-local identifier assigned by the sage (e.g. `obs-1`).
94	 * - `title` — one-line commission-title style (imperative or noun
95	 *   phrase, ~10 words, no trailing punctuation). Becomes the title of
96	 *   the lifted draft writ.
97	 * - `body` — tactical detail (file paths, symbols, preconditions)
98	 *   rendered as markdown. Becomes the body of the lifted draft writ.
99	 */
100	export interface Observation {
101	  id: string;
102	  title: string;
103	  body: string;
104	}
105	
106	export interface Decision {
107	  id: string;
108	  scope: string[];
109	  question: string;
110	  context?: string;
111	  options: Record<string, string>;
112	  recommendation?: string;
113	  rationale?: string;
114	  selected?: string;
115	  patronOverride?: string;
116	  /**
117	   * Patron Anima emission for this decision, if the patron-anima engine
118	   * touched it. Records the anima's verdict, selection, confidence, and
119	   * short rationale. Kept distinct from primer fields so override-rate ×
120	   * confidence can be measured as a first-class planner-quality signal.
121	   */
122	  patron?: PatronEmission;
123	}
124	
125	/**
126	 * A Patron Anima's emission for a single decision.
127	 *
128	 * - `verdict: 'confirm'` — the anima accepts the primer's recommendation.
129	 * - `verdict: 'override'` — the anima picks a different option than the
130	 *   recommendation.
131	 * - `verdict: 'fill-in'` — no primer recommendation existed; the anima
132	 *   supplies one.
133	 *
134	 * `selection` must be one of the decision's offered option keys — the
135	 * anima cannot emit custom / free-text selections. (The human patron
136	 * retains that escape hatch via `decision-review`'s `allowCustom` input.)
137	 *
138	 * `confidence` is calibrated structurally against the patron role's
139	 * principles list: one principle applies cleanly → `'high'`; multiple
140	 * principles conflict (and the anima resolves the conflict) → `'med'`;
141	 * no principle applies → `'low'`. A `'low'` verdict is always `'confirm'`
142	 * — principle-absence is the first-class signal for "no principled basis
143	 * to differ from the primer." Abstention (narrow: irresolvable principle
144	 * conflict or broken decision frame) is encoded as absence from the
145	 * emission array, not as a `PatronEmission`.
146	 *
147	 * `rationale` is a short free-text note — which principle (or conflict)
148	 * produced the verdict. Optional so the engine can accept minimal well-
149	 * formed emissions.
150	 */
151	export interface PatronEmission {
152	  verdict: 'confirm' | 'override' | 'fill-in';
153	  selection: string;
154	  confidence: 'low' | 'med' | 'high';
155	  rationale?: string;
156	}
157	
158	// ── Filters ──────────────────────────────────────────────────────────
159	
160	export interface PlanFilters {
161	  /** Filter by status. */
162	  status?: PlanStatus;
163	  /** Filter by codex name. */
164	  codex?: string;
165	  /** Maximum number of results (default: 20). */
166	  limit?: number;
167	  /** Number of results to skip. */
168	  offset?: number;
169	}
170	
171	// ── Configuration ────────────────────────────────────────────────────
172	
173	export interface AstrolabeConfig {
174	  /**
175	   * Qualified role name of the Patron Anima consulted by the
176	   * `astrolabe.patron-anima` engine before `decision-review`. When unset
177	   * or empty, the engine no-ops and `decision-review` proceeds as it
178	   * does without the anima stage. There is no framework default — every
179	   * patron's taste is unique, so a shared default would represent no
180	   * patron's taste.
181	   */
182	  patronRole?: string;
183	  /**
184	   * Soft-warn threshold for the predicted-files cost signal. The
185	   * `astrolabe.plan-finalize` engine emits the
186	   * `astrolabe.plan.files-over-threshold` Clockworks event when a plan's
187	   * `manifestFilesCount` strictly exceeds this value. Defaults to 15
188	   * when unset. Must be a positive integer when supplied — the resolver
189	   * fails loud on malformed values (wrong type, NaN, negative, zero,
190	   * non-integer) so a typo cannot silently mask the operator's intent.
191	   * The framework does not gate the pipeline on this signal; subscribers
192	   * decide how to react.
193	   */
194	  predictedFilesThreshold?: number;
195	}
196	
197	declare module '@shardworks/nexus-core' {
198	  interface GuildConfig {
199	    astrolabe?: AstrolabeConfig;
200	  }
201	}
202	
203	// ── API ──────────────────────────────────────────────────────────────
204	
205	export interface AstrolabeApi {
206	  /** Show a plan by id. Throws if not found. */
207	  show(planId: string): Promise<PlanDoc>;
208	  /** List plans with optional filters, ordered by createdAt descending. */
209	  list(filters?: PlanFilters): Promise<PlanDoc[]>;
210	  /** Partially update a plan. Returns the updated document. Throws if not found. */
211	  patch(planId: string, fields: Partial<Omit<PlanDoc, 'id'>>): Promise<PlanDoc>;
212	}
