```typescript
const writsBook = stacks.readBook<WritDoc>('clerk', 'writs');
const docs = await writsBook.find({
  where: [
    ['type', '=', 'vision'],
    ...(filters?.stage !== undefined ? [['ext.cartograph.stage', '=', filters.stage]] : []),
